// userMenuDispatch builds the JS that fires the fc:user-menu CustomEvent
// from the row element (which carries the data-* identity). xExpr/yExpr
// are JS expressions for the popup anchor — cursor for right-click, the
// button's rect for the touch button.
func userMenuDispatch(xExpr, yExpr string) string {
	return "el.dispatchEvent(new CustomEvent('fc:user-menu',{bubbles:true,detail:{" +
		"id:el.dataset.userId,mid:el.dataset.membershipId,name:el.dataset.name," +
		"role:el.dataset.role,online:el.dataset.online==='1',banned:el.dataset.banned==='1'," +
		"blocked:el.dataset.blocked==='1',x:" + xExpr + ",y:" + yExpr + "}}))"
}

// rosterMenuBtnDispatch is the ⋮ touch-button handler: climb to the row
// li (the element holding the data-* identity), anchor the popup at the
// button's bottom-left, and dispatch the same event.
func rosterMenuBtnDispatch() string {
	return "const li=el.closest('.roster-row');const r=el.getBoundingClientRect();" +
		"li.dispatchEvent(new CustomEvent('fc:user-menu',{bubbles:true,detail:{" +
		"id:li.dataset.userId,mid:li.dataset.membershipId,name:li.dataset.name," +
		"role:li.dataset.role,online:li.dataset.online==='1',banned:li.dataset.banned==='1'," +
		"blocked:li.dataset.blocked==='1',x:r.left,y:r.bottom}}))"
}

// boolDigit renders a bool as "1"/"0" for a data-* attribute the menu
// dispatch coerces back to a JS boolean.
func boolDigit(b bool) string {
	if b {
		return "1"
	}
	return "0"
}

